import{_ as s,c as a,o as n,a as e}from"./app.6f6e89c1.js";const p="/assets/img1.7a90de32.webp",v=JSON.parse('{"title":"VPN 分流（内部服务才走 VPN）🚀","description":"","frontmatter":{},"headers":[{"level":2,"title":"1、问题","slug":"_1、问题","link":"#_1、问题","children":[]},{"level":2,"title":"2、解决方法","slug":"_2、解决方法","link":"#_2、解决方法","children":[{"level":3,"title":"2.1 VPN 配置关闭“通过 VPN 连接发送所有流量”","slug":"_2-1-vpn-配置关闭-通过-vpn-连接发送所有流量","link":"#_2-1-vpn-配置关闭-通过-vpn-连接发送所有流量","children":[]},{"level":3,"title":"2.2 查询需要访问的内部服务 ip","slug":"_2-2-查询需要访问的内部服务-ip","link":"#_2-2-查询需要访问的内部服务-ip","children":[]},{"level":3,"title":"2.3 添加配置文件","slug":"_2-3-添加配置文件","link":"#_2-3-添加配置文件","children":[]}]},{"level":2,"title":"3、一键脚本","slug":"_3、一键脚本","link":"#_3、一键脚本","children":[]}],"relativePath":"technology/network/vpn-shunt.md","lastUpdated":1671588986000}'),l={name:"technology/network/vpn-shunt.md"},t=e('<h1 id="vpn-分流-内部服务才走-vpn-🚀" tabindex="-1">VPN 分流（内部服务才走 VPN）🚀 <a class="header-anchor" href="#vpn-分流-内部服务才走-vpn-🚀" aria-hidden="true">#</a></h1><h2 id="_1、问题" tabindex="-1">1、问题 <a class="header-anchor" href="#_1、问题" aria-hidden="true">#</a></h2><p>经常在家办公，遇到两个问题：</p><ul><li>不连接 VPN，无法访问 git 仓库等内部服务</li><li>连接 VPN，全部流量都要到公司网络转一圈，速度很慢</li></ul><h2 id="_2、解决方法" tabindex="-1">2、解决方法 <a class="header-anchor" href="#_2、解决方法" aria-hidden="true">#</a></h2><p>VPN 分流，只允许公司内部服务走 VPN，其他流量走本地</p><h3 id="_2-1-vpn-配置关闭-通过-vpn-连接发送所有流量" tabindex="-1">2.1 VPN 配置关闭“通过 VPN 连接发送所有流量” <a class="header-anchor" href="#_2-1-vpn-配置关闭-通过-vpn-连接发送所有流量" aria-hidden="true">#</a></h3><p><img src="'+p+`" alt=""> 系统 macOS 13 界面 界面配置</p><h3 id="_2-2-查询需要访问的内部服务-ip" tabindex="-1">2.2 查询需要访问的内部服务 ip <a class="header-anchor" href="#_2-2-查询需要访问的内部服务-ip" aria-hidden="true">#</a></h3><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">➜  </span><span style="color:#89DDFF;">~</span><span style="color:#A6ACCD;"> nslookup github.com</span></span>
<span class="line"><span style="color:#A6ACCD;">Server:		8.8.8.8</span></span>
<span class="line"><span style="color:#A6ACCD;">Address:	8.8.8.8#53</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">Non-authoritative answer:</span></span>
<span class="line"><span style="color:#A6ACCD;">Name:	github.com</span></span>
<span class="line"><span style="color:#A6ACCD;">Address: 20.205.243.166</span></span>
<span class="line"></span></code></pre></div><h3 id="_2-3-添加配置文件" tabindex="-1">2.3 添加配置文件 <a class="header-anchor" href="#_2-3-添加配置文件" aria-hidden="true">#</a></h3><p>添加文件 <code>sudo vi /etc/ppp/ip-up</code>，添加如下内容：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;">#!/bin/sh</span></span>
<span class="line"><span style="color:#A6ACCD;">/sbin/route add -net 20.205.243.166/32 -interface ppp0</span></span>
<span class="line"></span></code></pre></div><p>保存退出赋权限<code>sudo chmod 0755 /etc/ppp/ip-up</code></p><p>断开 VPN 重新连接。这样<code>内部服务</code>的流量就走 vpn，其他走本地</p><h2 id="_3、一键脚本" tabindex="-1">3、一键脚本 <a class="header-anchor" href="#_3、一键脚本" aria-hidden="true">#</a></h2><p>复制到命令行运行：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">sudo touch /etc/ppp/ip-up</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo chmod 0777 /etc/ppp/ip-up</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo cat</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">/etc/ppp/ip-up</span><span style="color:#89DDFF;">&lt;&lt;</span><span style="color:#89DDFF;">EOF</span></span>
<span class="line"><span style="color:#C3E88D;">#!/bin/sh</span></span>
<span class="line"><span style="color:#C3E88D;">/sbin/route add -net 20.205.243.166/32 -interface ppp0</span></span>
<span class="line"><span style="color:#89DDFF;">EOF</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo chmod 0755 /etc/ppp/ip-up</span></span>
<span class="line"></span></code></pre></div><p>断开 VPN 重新连接后生效</p>`,19),c=[t];function o(i,r,d,h,_,u){return n(),a("div",null,c)}const A=s(l,[["render",o]]);export{v as __pageData,A as default};
